          <text x="155" y="132" textAnchor="middle" fontFamily={fontSans} fontSize="9" fill="#fff" fontWeight="700">Delegování</text>

          {/* S1 Přikazování — vpravo nahoře (vysoká direktivita, nízká podpora) */}
          <circle cx="345" cy="120" r="38" fill={VSE.danger} opacity="0.9"/>
