          {/* Vývoj šipka */}
          <text x="250" y="25" textAnchor="middle" fontFamily={fontMono} fontSize="10" fill={VSE.primary} fontWeight="700" fontStyle="italic">Vývoj pracovníka: D1 → D2 → D3 → D4</text>
